import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
* Sends a request to the server asking for
* profile achievements for a specific user.
*/
export class ProfileAchievementsRequestComposer
implements IMessageComposer<any[]>
{
private _data: any[];

constructor(userId: number)
{
this._data = [ userId ];
console.log('[📤] ProfileAchievementsRequestComposer sent for:', userId);
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}